INSERT INTO DELIVERY_DETAIL (
    DELIVERY_DETAIL_NO, DELIVERY_NO, STATUS, SHIPPED_DATE
) VALUES (
    SEQ_DELIVERY_DETAIL_NO.NEXTVAL, #{deliveryNo}, 'S', SYSDATE
)

