BEGIN
    UPDATE ITEM SET PAY_STATUS = 'S' WHERE ITEM_NO = #{itemNo};
    UPDATE PAYMENT SET PAY_STATUS = 'S' WHERE PAY_NO = #{paymentNo};
END;

BEGIN
    UPDATE PAYMENT SET PAY_STATUS = 'P' WHERE PAY_NO = #{paymentNo};

    UPDATE DELIVERY_DETAIL 
    SET STATUS = 'P', 
        DELIVERED_DATE = SYSDATE 
    WHERE DELIVERY_NO = (
        SELECT DELIVERY_NO FROM DELIVERY WHERE PAYMENT_NO = #{paymentNo}
    );
END;
